// Extract research data from researcher agent
const research = $input.first().json;
let researchData;

try {
  const text = research.text || research.content || JSON.stringify(research);
  // Try to parse JSON from response
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    researchData = JSON.parse(jsonMatch[0]);
  } else {
    researchData = {
      key_points: [text.substring(0, 500)],
      sources: [],
      insights: []
    };
  }
} catch {
  researchData = {
    key_points: ['Research data extraction failed'],
    sources: [],
    insights: []
  };
}

return {
  topic: $('Webhook Trigger').item.json.body.topic,
  audience: $('Webhook Trigger').item.json.body.audience,
  format: $('Webhook Trigger').item.json.body.format,
  research: researchData,
  researcher_tokens: research.usage?.total_tokens || 0
};

// Final processing - aggregate all agent outputs
const editorResponse = $input.first().json;
let editorData;

try {
  const text = editorResponse.text || editorResponse.content || JSON.stringify(editorResponse);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    editorData = JSON.parse(jsonMatch[0]);
  } else {
    editorData = {
      edited_content: text,
      changes_made: [],
      quality_score: 75
    };
  }
} catch {
  editorData = {
    edited_content: editorResponse.text || 'Processing error',
    changes_made: [],
    quality_score: 70
  };
}

const extractData = $('Extract Research Data').first().json;
const writerData = $('Writer Agent').first().json;

return {
  topic: extractData.topic,
  final_content: editorData.edited_content,
  quality_score: editorData.quality_score,
  changes_made: editorData.changes_made,
  pipeline_stats: {
    researcher_tokens: extractData.researcher_tokens,
    writer_tokens: writerData.usage?.total_tokens || 0,
    editor_tokens: editorResponse.usage?.total_tokens || 0,
    total_agents: 3
  },
  timestamp: new Date().toISOString()
};
